#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b) { return (*(int*)a) - (*(int*)b); }
int canPlace(int *pos, int n, int c, int d) {
    int placed = 1;
    int last = pos[0];
    for (int i = 1; i < n; ++i) {
        if (pos[i] - last >= d) {
            placed++;
            last = pos[i];
            if (placed == c) return 1;
        }
    }
    return 0;
}
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, c; scanf("%d %d", &n, &c);
        int *arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        qsort(arr, n, sizeof(int), cmp);
        int low = 0, high = arr[n-1] - arr[0], ans = 0;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (canPlace(arr, n, c, mid)) { ans = mid; low = mid + 1; }
            else high = mid - 1;
        }
        printf("%d\n", ans);
        free(arr);
    }
    return 0;
}

