import sys

def can_place(pos, c, d):
    placed = 1
    last = pos[0]
    for x in pos[1:]:
        if x - last >= d:
            placed += 1
            last = x
            if placed == c:
                return True
    return False

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it)); c = int(next(it))
        pos = [int(next(it)) for _ in range(n)]
        pos.sort()
        low, high = 0, pos[-1] - pos[0]
        ans = 0
        while low <= high:
            mid = (low + high) // 2
            if can_place(pos, c, mid):
                ans = mid
                low = mid + 1
            else:
                high = mid - 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

